import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface RolePlayer {
  id: string;
  role: string;
  name: string;
  photoUrl: string | null;
}

export interface MeetingDetails {
  title: string;
  theme: string;
  date: string;
  time: string;
  location: string;
  clubName: string;
}

export interface FlyerConfig {
  details: MeetingDetails;
  roles: RolePlayer[];
  backgroundUrl: string | null;
}

import { GoogleGenAI } from "@google/genai";

export async function generateFlyerBackground(theme: string): Promise<string | null> {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    const prompt = `Create a professional, modern, and high-quality background for a Toastmasters meeting flyer. 
    The meeting theme is "${theme}". 
    The design should be clean, abstract, and corporate-appropriate. 
    Use a sophisticated color palette including deep navy blue, maroon, and elegant gold highlights. 
    Ensure there is plenty of clean space for text overlays. 
    The style should be inspiring and welcoming.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }]
      },
      config: {
        imageConfig: {
          aspectRatio: "9:16"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    return null;
  } catch (error) {
    console.error("Error generating background:", error);
    return null;
  }
}

