}

const FlyerCanvas: React.FC<FlyerCanvasProps> = ({ details, roles, backgroundUrl }) => {
  // Helper to find roles by name (case-insensitive)
  const findRoles = (keywords: string[]) => 
    roles.filter(r => keywords.some(k => r.role.toUpperCase().includes(k.toUpperCase())));

  // Category 1: TMOD, TTM, General Evaluator
  const cat1 = findRoles(['TMOD', 'TTM', 'EVALUATOR']).filter(r => !r.role.toUpperCase().match(/\d/)); 

  // Category 2: Timer, Ah Counter, Grammarian
  const cat2 = findRoles(['TIMER', 'AH COUNTER', 'GRAMMARIAN']);

  // Category 3: Speaker 1, Speaker 2, Evaluator 1, Evaluator 2
  const cat3 = findRoles(['SPEAKER', 'EVALUATOR']).filter(r => r.role.toUpperCase().match(/\d/));

  // Fallback for custom roles not in standard list
  const allCategorizedIds = new Set([...cat1, ...cat2, ...cat3].map(r => r.id));
  const remaining = roles.filter(r => !allCategorizedIds.has(r.id) && (r.name || r.role));

