import { GoogleGenAI } from "@google/genai";

export async function generateFlyerBackground(theme: string): Promise<string | null> {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    const prompt = `Create a professional, modern, and high-quality background for a Toastmasters International meeting flyer. 
    The meeting theme is "${theme}". 
    The design MUST use the official Toastmasters color palette: 
    - Loyal Blue (#004165)
    - True Maroon (#772432)
    - Happy Yellow (#F2DF74)
    - Cool Grey (#A9B2B1)

    The style should be corporate yet inspiring, abstract with clean lines. 
    Ensure a large portion of the image is subtle or has dark space (especially using Loyal Blue or True Maroon) to allow for legible white text overlays. 
    Avoid people in the image; focus on abstract shapes, light flares, or symbolic representations of communication and leadership.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }]
      },
      config: {
        imageConfig: {
          aspectRatio: "3:4"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    return null;
  } catch (error) {
    console.error("Error generating background:", error);
    return null;
  }
}

export async function generateRoleAvatar(role: string, theme: string): Promise<string | null> {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    const prompt = `A professional portrait of a person suitable for a Toastmasters meeting role: "${role}". 
    The meeting theme is "${theme}". 
    The style should be a high-quality, professional headshot with a clean, slightly blurred office or library background. 
    The person should look confident, friendly, and professional. 
    The lighting should be studio-quality. 
    Maintain a corporate and polished aesthetic. 
    Ensure the person is centered and the portrait is a close-up headshot.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    return null;
  } catch (error) {
    console.error("Error generating role avatar:", error);
    return null;
  }
}

import React, { useState, useRef } from 'react';
import { Plus, Trash2, Camera, Download, Sparkles, Award, Printer, Image as ImageIcon, Loader2 } from 'lucide-react';
import { RolePlayer, MeetingDetails } from './types';
import { generateFlyerBackground, generateRoleAvatar } from './geminiService';
import FlyerCanvas from './components/FlyerCanvas';
import { toPng } from 'html-to-image';

const DEFAULT_ROLES = [
  "TMOD",
  "TTM",
  "GENERAL EVALUATOR",
  "TIMER",
  "AH COUNTER",
  "GRAMMARIAN",
  "SPEAKER 1",
  "SPEAKER 2",
  "EVALUATOR 1",
  "EVALUATOR 2"
];

const App: React.FC = () => {
  const flyerRef = useRef<HTMLDivElement>(null);
  const [details, setDetails] = useState<MeetingDetails>({
    title: "Meeting Invitation",
    theme: "The Art of Listening",
    date: new Date().toISOString().split('T')[0],
    time: "19:00",
    location: "Community Center / Zoom",
    clubName: "Your Club Name"
  });

  const [roles, setRoles] = useState<RolePlayer[]>(
    DEFAULT_ROLES.map((role) => ({
      id: Math.random().toString(36).substr(2, 9),
      role,
      name: "",
      photoUrl: null
    }))
  );

  const [isGeneratingBg, setIsGeneratingBg] = useState(false);
  const [isGeneratingAllPhotos, setIsGeneratingAllPhotos] = useState(false);
  const [generatingRoleIds, setGeneratingRoleIds] = useState<Set<string>>(new Set());
  const [isDownloading, setIsDownloading] = useState(false);
  const [backgroundUrl, setBackgroundUrl] = useState<string | null>(null);

  const addRole = () => {
    setRoles([...roles, {
      id: Math.random().toString(36).substr(2, 9),
      role: "",
      name: "",
      photoUrl: null
    }]);
  };

  const removeRole = (id: string) => {
    setRoles(roles.filter(r => r.id !== id));
  };

  const updateRole = (id: string, updates: Partial<RolePlayer>) => {
    setRoles(roles.map(r => r.id === id ? { ...r, ...updates } : r));
  };

  const handlePhotoUpload = (id: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateRole(id, { photoUrl: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleMagicPhoto = async (id: string, roleName: string) => {
    setGeneratingRoleIds(prev => new Set(prev).add(id));
    const url = await generateRoleAvatar(roleName || "Toastmaster", details.theme);
    if (url) {
      updateRole(id, { photoUrl: url });
    }
    setGeneratingRoleIds(prev => {
      const next = new Set(prev);
      next.delete(id);
      return next;
    });
  };

  const handleMagicFillAll = async () => {
    setIsGeneratingAllPhotos(true);
    // Process in small batches to avoid hitting rate limits or crashing
    const rolesToFill = roles.filter(r => !r.photoUrl);

    for (const role of rolesToFill) {
      setGeneratingRoleIds(prev => new Set(prev).add(role.id));
      const url = await generateRoleAvatar(role.role || "Toastmaster", details.theme);
      if (url) {
        setRoles(currentRoles => currentRoles.map(r => r.id === role.id ? { ...r, photoUrl: url } : r));
      }
      setGeneratingRoleIds(prev => {
        const next = new Set(prev);
        next.delete(role.id);
        return next;
      });
      // Small pause between generations
      await new Promise(r => setTimeout(r, 200));
    }
    setIsGeneratingAllPhotos(false);
  };

  const handleGenerateBackground = async () => {
    setIsGeneratingBg(true);
    const url = await generateFlyerBackground(details.theme);
    if (url) {
      setBackgroundUrl(url);
    }
    setIsGeneratingBg(false);
  };

  const handlePrint = () => {
    window.print();
  };

  const handleDownloadImage = async () => {
    if (!flyerRef.current) return;

    setIsDownloading(true);
    try {
      const dataUrl = await toPng(flyerRef.current, { 
        quality: 1, 
        pixelRatio: 4, 
        cacheBust: true 
      });

      const link = document.createElement('a');
      const fileName = `TM_Flyer_${details.theme.replace(/\s+/g, '_') || 'Meeting'}.png`;
      link.download = fileName;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      console.error('Failed to capture flyer image:', err);
      alert('Could not download image. Please try the "Print / Save PDF" option instead.');
    } finally {
      setIsDownloading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col lg:flex-row">
      {/* Sidebar / Editor */}
      <div className="w-full lg:w-1/2 p-6 lg:p-10 overflow-y-auto no-print">
        <header className="mb-8">
          <div className="flex items-center gap-2 text-tm-maroon mb-2">
            <Award className="w-8 h-8" />
            <h1 className="text-2xl font-bold font-brand tracking-tight">Toastmasters Flyer Pro</h1>
          </div>
          <p className="text-slate-500">Design elegant flyers for your club meetings in seconds.</p>
        </header>

        <section className="space-y-6">
          <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
            <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-4 border-b pb-2">Meeting Details</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-xs font-semibold text-slate-900">Club Name</label>
                <input 
                  type="text" 
                  className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-tm-blue outline-none transition-all text-slate-900 placeholder:text-slate-400"
                  value={details.clubName}
                  onChange={(e) => setDetails({ ...details, clubName: e.target.value })}
                  placeholder="Enter club name"
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-semibold text-slate-900">Meeting Theme</label>
                <input 
                  type="text" 
                  className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-tm-blue outline-none transition-all text-slate-900 placeholder:text-slate-400"
                  value={details.theme}
                  onChange={(e) => setDetails({ ...details, theme: e.target.value })}
                  placeholder="Enter meeting theme"
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-semibold text-slate-900">Date</label>
                <input 
                  type="date" 
                  className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-tm-blue outline-none transition-all text-slate-900"
                  value={details.date}
                  onChange={(e) => setDetails({ ...details, date: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-semibold text-slate-900">Time</label>
                <input 
                  type="time" 
                  className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-tm-blue outline-none transition-all text-slate-900"
                  value={details.time}
                  onChange={(e) => setDetails({ ...details, time: e.target.value })}
                />
              </div>
              <div className="md:col-span-2 space-y-2">
                <label className="text-xs font-semibold text-slate-900">Location</label>
                <input 
                  type="text" 
                  className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-tm-blue outline-none transition-all text-slate-900 placeholder:text-slate-400"
                  value={details.location}
                  onChange={(e) => setDetails({ ...details, location: e.target.value })}
                  placeholder="Meeting location or Zoom link"
                />
              </div>
            </div>
          </div>

          <div className="bg-tm-blue rounded-2xl p-6 shadow-lg text-white">
            <div className="flex justify-between items-center mb-4">
              <div>
                <h2 className="text-lg font-bold flex items-center gap-2">
                  <Sparkles className="w-5 h-5 text-tm-yellow" />
                  AI Background
                </h2>
                <p className="text-slate-300 text-sm">Generate a theme-based background.</p>
              </div>
              <button 
                onClick={handleGenerateBackground}
                disabled={isGeneratingBg}
                className="px-6 py-2 bg-white text-tm-blue rounded-full font-semibold hover:bg-tm-yellow hover:scale-105 active:scale-95 transition-all disabled:opacity-50 flex items-center gap-2 cursor-pointer"
              >
                {isGeneratingBg ? "Generating..." : "Magic Background"}
                <Sparkles className="w-4 h-4" />
              </button>
            </div>
            {backgroundUrl && (
              <div className="mt-4 h-32 w-full rounded-xl overflow-hidden bg-tm-blue/50 border-2 border-tm-blue/50">
                <img src={backgroundUrl} className="w-full h-full object-cover" alt="Generated background" />
              </div>
            )}
          </div>

          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <div className="flex flex-col">
                <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">Role Players</h2>
                <p className="text-xs text-slate-400">Add names or let AI generate photos.</p>
              </div>
              <div className="flex gap-2">
                <button 
                  onClick={handleMagicFillAll}
                  disabled={isGeneratingAllPhotos}
                  className="flex items-center gap-2 px-4 py-2 bg-tm-yellow text-tm-blue rounded-full font-bold text-xs hover:scale-105 active:scale-95 transition-all shadow-sm disabled:opacity-50 cursor-pointer"
                >
                  <Sparkles className="w-3.5 h-3.5" />
                  {isGeneratingAllPhotos ? "Filling..." : "Magic Fill All Photos"}
                </button>
                <button 
                  onClick={addRole}
                  className="p-2 bg-white text-tm-maroon rounded-full border border-slate-100 hover:bg-slate-50 transition-colors shadow-sm cursor-pointer"
                >
                  <Plus className="w-5 h-5" />
                </button>
              </div>
            </div>

            <div className="grid grid-cols-1 gap-4">
              {roles.map((role) => (
                <div key={role.id} className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm flex items-start gap-4 transition-all hover:border-tm-maroon/30 group/row">
                  <div className="relative">
                    <div className="w-16 h-16 rounded-full bg-slate-100 overflow-hidden border-2 border-slate-200 flex items-center justify-center relative">
                      {generatingRoleIds.has(role.id) ? (
                        <div className="absolute inset-0 bg-white/80 flex items-center justify-center z-10">
                          <Loader2 className="w-6 h-6 text-tm-blue animate-spin" />
                        </div>
                      ) : null}
                      {role.photoUrl ? (
                        <img src={role.photoUrl} className="w-full h-full object-cover" alt={role.name} />
                      ) : (
                        <Camera className="w-6 h-6 text-slate-400" />
                      )}
                    </div>
                    <div className="absolute -bottom-1 -right-1 flex flex-col gap-1">
                      <label className="p-1.5 bg-tm-blue text-white rounded-full cursor-pointer shadow-md hover:bg-tm-blue/90 transition-colors border border-white">
                        <Plus className="w-3 h-3" />
                        <input 
                          type="file" 
                          className="hidden" 
                          accept="image/*"
                          onChange={(e) => handlePhotoUpload(role.id, e)}
                        />
                      </label>
                      <button 
                        onClick={() => handleMagicPhoto(role.id, role.role)}
                        disabled={generatingRoleIds.has(role.id)}
                        className="p-1.5 bg-tm-yellow text-tm-blue rounded-full cursor-pointer shadow-md hover:scale-110 transition-all border border-white disabled:opacity-50"
                        title="AI Generate Photo"
                      >
                        <Sparkles className="w-3 h-3" />
                      </button>
                    </div>
                  </div>

                  <div className="flex-1 grid grid-cols-2 gap-3">
                    <div className="space-y-1">
                      <input 
                        placeholder="Role (e.g. Timer)"
                        className="w-full text-xs font-bold text-tm-blue border-none bg-transparent focus:ring-0 placeholder:text-slate-300"
                        value={role.role}
                        onChange={(e) => updateRole(role.id, { role: e.target.value })}
                      />
                      <input 
                        placeholder="Player Name"
                        className="w-full text-sm font-medium text-slate-900 border-none bg-transparent focus:ring-0 placeholder:text-slate-400"
                        value={role.name}
                        onChange={(e) => updateRole(role.id, { name: e.target.value })}
                      />
                    </div>
                    <div className="flex justify-end items-center">
                      <button 
                        onClick={() => removeRole(role.id)}
                        className="p-2 text-slate-300 hover:text-red-500 transition-colors opacity-0 group-hover/row:opacity-100"
                        title="Remove Role"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </section>
      </div>

      {/* Preview Section */}
      <div className="w-full lg:w-1/2 bg-slate-200 lg:min-h-screen flex flex-col items-center justify-center p-4 lg:p-10 sticky top-0 print:p-0 print:bg-white print:static print:w-full print:h-screen">
        <div className="mb-6 flex flex-col md:flex-row gap-4 no-print relative z-50">
          <button 
            type="button"
            onClick={handleDownloadImage}
            disabled={isDownloading}
            className="flex items-center gap-2 px-8 py-4 bg-tm-blue text-white rounded-xl font-bold hover:bg-[#003150] transition-all shadow-lg active:scale-95 cursor-pointer disabled:opacity-50"
          >
            <ImageIcon className="w-6 h-6" />
            <span className="text-lg">{isDownloading ? 'Processing...' : 'Download Flyer (PNG)'}</span>
          </button>

          <button 
            type="button"
            onClick={handlePrint}
            className="flex items-center gap-2 px-8 py-4 bg-tm-maroon text-white rounded-xl font-bold hover:bg-[#5a1b26] transition-all shadow-lg active:scale-95 cursor-pointer"
          >
            <Printer className="w-6 h-6" />
            <span className="text-lg">Print / Save PDF</span>
          </button>
        </div>

        <div 
          id="flyer-preview-container" 
          ref={flyerRef}
          className="w-full max-w-[600px] shadow-2xl overflow-hidden bg-white aspect-[3/4] rounded-sm relative print:shadow-none print:max-w-none print:rounded-none"
        >
          <FlyerCanvas 
            details={details} 
            roles={roles} 
            backgroundUrl={backgroundUrl} 
          />
        </div>
      </div>
    </div>
  );
};

