import React, { useState, useRef } from 'react';
import { Plus, Trash2, Camera, Download, Sparkles, Award, Printer, Image as ImageIcon, Loader2 } from 'lucide-react';
import { RolePlayer, MeetingDetails } from './types';
import { generateFlyerBackground, generateRoleAvatar } from './geminiService';
import FlyerCanvas from './components/FlyerCanvas';
import { toPng } from 'html-to-image';

const DEFAULT_ROLES = [
  "TMOD",
  "TTM",
  "GENERAL EVALUATOR",
  "TIMER",
  "AH COUNTER",
  "GRAMMARIAN",
  "SPEAKER 1",
  "SPEAKER 2",
  "EVALUATOR 1",
  "EVALUATOR 2"
];

const App: React.FC = () => {
  const flyerRef = useRef<HTMLDivElement>(null);
  const [details, setDetails] = useState<MeetingDetails>({
    title: "Meeting Invitation",
    theme: "The Art of Listening",
    date: new Date().toISOString().split('T')[0],
    time: "19:00",
    location: "Community Center / Zoom",
    clubName: "Your Club Name"
  });

  const [roles, setRoles] = useState<RolePlayer[]>(
    DEFAULT_ROLES.map((role) => ({
      id: Math.random().toString(36).substr(2, 9),
      role,
      name: "",
      photoUrl: null
    }))
  );

  const [isGeneratingBg, setIsGeneratingBg] = useState(false);
  const [isGeneratingAll, setIsGeneratingAll] = useState(false);
  const [generatingIds, setGeneratingIds] = useState<Set<string>>(new Set());
  const [isDownloading, setIsDownloading] = useState(false);
  const [backgroundUrl, setBackgroundUrl] = useState<string | null>(null);

  const addRole = () => {
    setRoles([...roles, {
      id: Math.random().toString(36).substr(2, 9),
      role: "",
      name: "",
      photoUrl: null
    }]);
  };

  const removeRole = (id: string) => {
    setRoles(roles.filter(r => r.id !== id));
  };

  const updateRole = (id: string, updates: Partial<RolePlayer>) => {
    setRoles(roles.map(r => r.id === id ? { ...r, ...updates } : r));
  };

  const handlePhotoUpload = (id: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateRole(id, { photoUrl: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleMagicPhoto = async (id: string, roleName: string) => {
    setGeneratingIds(prev => new Set(prev).add(id));
    const url = await generateRoleAvatar(roleName || "Speaker", details.theme);
    if (url) {
      updateRole(id, { photoUrl: url });
    }
    setGeneratingIds(prev => {
      const next = new Set(prev);
      next.delete(id);
      return next;
    });
  };

  const handleMagicFillAll = async () => {
    setIsGeneratingAll(true);
    for (const role of roles) {
      if (!role.photoUrl) {
        await handleMagicPhoto(role.id, role.role);
      }
    }
    setIsGeneratingAll(false);
  };

  const handleGenerateBackground = async () => {
    setIsGeneratingBg(true);
    const url = await generateFlyerBackground(details.theme);
    if (url) {
      setBackgroundUrl(url);
    }
    setIsGeneratingBg(false);
  };

  const handlePrint = () => {
    window.print();
  };

  const handleDownloadImage = async () => {
    if (!flyerRef.current) return;

    setIsDownloading(true);
    try {
      const dataUrl = await toPng(flyerRef.current, { 
        quality: 1, 
        pixelRatio: 4, 
        cacheBust: true 
      });

      const link = document.createElement('a');
      const fileName = `TM_Flyer_${details.theme.replace(/\s+/g, '_') || 'Meeting'}.png`;
      link.download = fileName;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      console.error('Failed to capture flyer image:', err);
      alert('Could not download image. Please try the "Print / Save PDF" option instead.');
    } finally {
      setIsDownloading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col lg:flex-row">
      <div className="w-full lg:w-1/2 p-6 lg:p-10 overflow-y-auto no-print">
        <header className="mb-8">
          <div className="flex items-center gap-2 text-tm-maroon mb-2">
            <Award className="w-8 h-8" />
            <h1 className="text-2xl font-bold font-brand tracking-tight">Toastmasters Flyer Pro</h1>
          </div>
          <p className="text-slate-500 text-sm">Design and generate meeting flyers with AI.</p>
        </header>

        <section className="space-y-6">
          <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
            <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-4 border-b pb-2">Meeting Details</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-xs font-semibold text-slate-900">Club Name</label>
                <input 
                  type="text" 
                  className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-tm-blue outline-none transition-all text-slate-900 placeholder:text-slate-400"
                  value={details.clubName}
                  onChange={(e) => setDetails({ ...details, clubName: e.target.value })}
                  placeholder="Enter club name"
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-semibold text-slate-900">Meeting Theme</label>
                <input 
                  type="text" 
                  className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-tm-blue outline-none transition-all text-slate-900 placeholder:text-slate-400"
                  value={details.theme}
                  onChange={(e) => setDetails({ ...details, theme: e.target.value })}
                  placeholder="Enter meeting theme"
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-semibold text-slate-900">Date</label>
                <input 
                  type="date" 
                  className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-tm-blue outline-none transition-all text-slate-900"
                  value={details.date}
                  onChange={(e) => setDetails({ ...details, date: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-semibold text-slate-900">Time</label>
                <input 
                  type="time" 
                  className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-tm-blue outline-none transition-all text-slate-900"
                  value={details.time}
                  onChange={(e) => setDetails({ ...details, time: e.target.value })}
                />
              </div>
              <div className="md:col-span-2 space-y-2">
                <label className="text-xs font-semibold text-slate-900">Location</label>
                <input 
                  type="text" 
                  className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-tm-blue outline-none transition-all text-slate-900 placeholder:text-slate-400"
