          <div className="bg-tm-maroon/80 py-0.5 px-4 rounded-full border border-tm-yellow/20 mt-1 shadow-lg">
            <p className="text-[8px] sm:text-[10px] font-bold text-tm-yellow italic tracking-wide">
              Theme: {details.theme}
            </p>
          </div>
        </div>

        {/* Roles Section - Grouped as requested */}
        <div className="flex-1 flex flex-col gap-3 sm:gap-5 min-h-0 overflow-y-auto no-scrollbar">

          {/* Group 1: Leadership */}
          {cat1.length > 0 && (
            <div className="flex flex-col gap-1.5">
              <div className="flex items-center gap-1.5 border-b border-tm-yellow/20 pb-0.5">
                <Shield className="w-2.5 h-2.5 text-tm-yellow" />
