import React, { useState, useRef } from 'react';
import { Plus, Trash2, Camera, Download, Sparkles, Award, Printer, Image as ImageIcon, Loader2, Sliders, Layout, Square, Circle, EyeOff, AlignCenter, Grid, Rows } from 'lucide-react';
import { RolePlayer, MeetingDetails } from './types';
import { generateFlyerBackground, generateRoleAvatar } from './geminiService';
import FlyerCanvas from './components/FlyerCanvas';
import { toPng } from 'html-to-image';

const DEFAULT_ROLES = [
  "TMOD",
  "TTM",
  "General Evaluator",
  "Timer",
  "Ah Counter",
  "Grammarian",
  "Speaker 1",
  "Speaker 2",
  "Evaluator 1",
  "Evaluator 2"
];

const App: React.FC = () => {
  const flyerRef = useRef<HTMLDivElement>(null);
  const [details, setDetails] = useState<MeetingDetails>({
    title: "Meeting Invitation",
    theme: "The Art of Listening",
    date: new Date().toISOString().split('T')[0],
    time: "19:00",
    location: "Community Center / Zoom",
    clubName: "Your Club Name"
  });

  const [roles, setRoles] = useState<RolePlayer[]>(
    DEFAULT_ROLES.map((role) => ({
      id: Math.random().toString(36).substr(2, 9),
      role,
      name: "",
      photoUrl: null
    }))
  );

  const [isGeneratingBg, setIsGeneratingBg] = useState(false);
  const [generatingIds, setGeneratingIds] = useState<Set<string>>(new Set());
  const [isDownloading, setIsDownloading] = useState(false);
  const [backgroundUrl, setBackgroundUrl] = useState<string | null>(null);
  const [bgOpacity, setBgOpacity] = useState(100);
  const [photoStyle, setPhotoStyle] = useState<'circle' | 'square' | 'none'>('circle');
  const [layoutPattern, setLayoutPattern] = useState<'standard' | 'staggered' | 'focus'>('standard');

  const addRole = () => {
    setRoles([...roles, {
      id: Math.random().toString(36).substr(2, 9),
      role: "",
      name: "",
      photoUrl: null
    }]);
  };

  const removeRole = (id: string) => {
    setRoles(roles.filter(r => r.id !== id));
  };

  const updateRole = (id: string, updates: Partial<RolePlayer>) => {
    setRoles(roles.map(r => r.id === id ? { ...r, ...updates } : r));
  };

  const handlePhotoUpload = (id: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateRole(id, { photoUrl: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleMagicPhoto = async (id: string, roleName: string) => {
    setGeneratingIds(prev => new Set(prev).add(id));
    const url = await generateRoleAvatar(roleName || "Speaker", details.theme);
    if (url) {
      updateRole(id, { photoUrl: url });
    }
    setGeneratingIds(prev => {
      const next = new Set(prev);
      next.delete(id);
      return next;
    });
  };

  const handleGenerateBackground = async () => {
    setIsGeneratingBg(true);
    const url = await generateFlyerBackground(details.theme);
    if (url) {
      setBackgroundUrl(url);
    }
    setIsGeneratingBg(false);
  };

  const handlePrint = () => {
    window.print();
  };

  const handleDownloadImage = async () => {
    if (!flyerRef.current) return;
    setIsDownloading(true);
    try {
      const dataUrl = await toPng(flyerRef.current, { 
        quality: 1, 
        pixelRatio: 4, 
        cacheBust: true 
      });
      const link = document.createElement('a');
      link.download = `TM_Flyer_${details.theme.replace(/\s+/g, '_')}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      console.error('Failed to capture flyer image:', err);
      alert('Download failed. Try Print / Save PDF.');
    } finally {
      setIsDownloading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col lg:flex-row">
      {/* Editor Panel */}
      <div className="w-full lg:w-1/2 p-6 lg:p-10 overflow-y-auto no-print">
        <header className="mb-8">
          <div className="flex items-center gap-2 text-tm-maroon mb-2">
            <Award className="w-8 h-8" />
            <h1 className="text-2xl font-bold font-brand tracking-tight">Toastmasters Flyer Pro</h1>
          </div>
          <p className="text-slate-500 text-sm">Design professional meeting flyers with AI.</p>
        </header>

        <section className="space-y-6">
          {/* Meeting Details Card */}
          <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
