import React from 'react';
import { MapPin, Calendar, Clock, Award, Users, Shield, Zap, MessageSquare } from 'lucide-react';
import { RolePlayer, MeetingDetails } from '../types';

interface FlyerCanvasProps {
  details: MeetingDetails;
  roles: RolePlayer[];
  backgroundUrl: string | null;
  bgOpacity: number;
  photoStyle: 'circle' | 'square' | 'none';
  layoutPattern: 'standard' | 'staggered' | 'focus';
}

const FlyerCanvas: React.FC<FlyerCanvasProps> = ({ details, roles, backgroundUrl, bgOpacity, photoStyle, layoutPattern }) => {
  // Categorization logic based on keywords
  const findRoles = (keywords: string[]) => 
    roles.filter(r => keywords.some(k => r.role.toUpperCase().includes(k.toUpperCase())));

  const leadership = findRoles(['TMOD', 'TTM', 'GENERAL EVALUATOR', 'GE']).filter(r => !r.role.toUpperCase().match(/\d/)); 
  const support = findRoles(['TIMER', 'AH COUNTER', 'GRAMMARIAN']);
  const standardRoles = findRoles(['SPEAKER', 'EVALUATOR']).filter(r => r.role.toUpperCase().match(/\d/));

  const allCategorizedIds = new Set([...leadership, ...support, ...standardRoles].map(r => r.id));
  const remaining = roles.filter(r => !allCategorizedIds.has(r.id) && (r.name || r.role));

  const RoleItem = ({ role, isFocused = false, index = 0 }: { role: RolePlayer, isFocused?: boolean, index?: number }) => {
    const frameClass = photoStyle === 'circle' ? 'rounded-full' : 'rounded-xl';

    // Scale up for focus mode
    const sizeClasses = isFocused && layoutPattern === 'focus' 
      ? 'w-20 h-20 sm:w-24 sm:h-24 lg:w-28 lg:h-28' 
      : 'w-14 h-14 sm:w-16 sm:h-16 lg:w-20 lg:h-20';

    // Animation / Offset for staggered
    const staggeredClass = layoutPattern === 'staggered' && index % 2 !== 0 ? 'mt-4 sm:mt-6' : '';

    return (
      <div className={`flex flex-col items-center group animate-in fade-in zoom-in duration-300 ${staggeredClass}`}>
        {photoStyle !== 'none' && (
          <div className="relative mb-1.5">
            <div className={`${sizeClasses} ${frameClass} border-[3px] border-tm-yellow/40 overflow-hidden bg-tm-blue/40 shadow-xl group-hover:border-tm-yellow transition-all duration-300`}>
              {role.photoUrl ? (
                <img src={role.photoUrl} className="w-full h-full object-cover" alt={role.name} />
              ) : (
                <div className="w-full h-full flex items-center justify-center">
                  <Users className="w-1/2 h-1/2 text-tm-yellow/10" />
                </div>
              )}
            </div>
          </div>
        )}
        <div className={`text-center ${photoStyle === 'none' ? 'max-w-none' : 'max-w-[80px] sm:max-w-[120px]'}`}>
          <p className={`${photoStyle === 'none' ? 'text-[8px] sm:text-[10px]' : 'text-[7px] sm:text-[8px]'} font-black text-tm-yellow uppercase tracking-tight leading-none mb-1 truncate drop-shadow-sm`}>
            {role.role}
          </p>
          <p className={`${photoStyle === 'none' ? 'text-[10px] sm:text-[13px]' : 'text-[9px] sm:text-[11px]'} font-bold text-white leading-none drop-shadow-lg truncate`}>
            {role.name || "TBA"}
          </p>
        </div>
      </div>
    );
  };

  return (
    <div className="relative w-full h-full flex flex-col font-sans overflow-hidden bg-tm-blue">
      {/* Background Layer with Opacity Control */}
      <div className="absolute inset-0 z-0">
        {backgroundUrl ? (
          <img 
            src={backgroundUrl} 
            className="w-full h-full object-cover transition-opacity duration-300" 
            style={{ opacity: bgOpacity / 100 }}
            alt="Flyer Background" 
          />
        ) : (
          <div className="w-full h-full bg-gradient-to-br from-tm-blue via-tm-blue to-tm-maroon" />
        )}
        <div className="absolute inset-0 bg-gradient-to-t from-black/95 via-black/40 to-black/10" />
      </div>

      {/* Content Layer */}
      <div className="relative z-10 flex flex-col h-full text-white p-4 sm:p-6 lg:p-8 pt-6">
        <div className="absolute top-0 right-0 left-0 h-1 bg-tm-yellow shadow-sm" />

        {/* Header */}
        <div className="mb-4 flex flex-col items-center text-center">
          <div className="flex items-center gap-2 mb-1 opacity-95">
            <Award className="w-5 h-5 text-tm-yellow" />
            <div className="flex flex-col text-left">
              <span className="text-[6px] lg:text-[7px] font-black tracking-[0.4em] uppercase text-tm-yellow leading-none">TOASTMASTERS INTERNATIONAL</span>
              <span className="text-[10px] lg:text-[12px] font-bold uppercase tracking-widest text-white leading-tight drop-shadow-md">{details.clubName}</span>
            </div>
          </div>

          <h1 className="text-xl sm:text-2xl lg:text-3xl font-header font-black mb-1 text-white drop-shadow-2xl leading-tight">
            {details.title.toUpperCase()}
          </h1>

          <div className="bg-tm-maroon/90 py-0.5 px-6 rounded-full border border-tm-yellow/30 mt-1 shadow-2xl">
            <p className="text-[9px] sm:text-[11px] font-bold text-tm-yellow italic tracking-wide">
              Theme: {details.theme}
            </p>
          </div>
        </div>

        {/* Roles Section - Patterned Layouts */}
        <div className={`flex-1 flex flex-col ${photoStyle === 'none' ? 'gap-6 sm:gap-8' : 'gap-4 sm:gap-6'} min-h-0 overflow-y-auto no-scrollbar`}>

          {/* Category: Leadership */}
          {leadership.length > 0 && (
            <div className="flex flex-col gap-2">
              <div className="flex items-center gap-2 border-b border-tm-yellow/20 pb-0.5">
                <Shield className="w-3 h-3 text-tm-yellow" />
                <h3 className="text-[7px] lg:text-[8px] font-black tracking-[0.2em] uppercase text-tm-yellow">LEADERSHIP</h3>
              </div>
              <div className={`flex justify-center flex-wrap ${photoStyle === 'none' ? 'gap-10' : 'gap-6 sm:gap-12'} ${layoutPattern === 'focus' ? 'py-4' : ''}`}>
                {leadership.map((role, i) => (
                  <RoleItem key={role.id} role={role} isFocused={true} index={i} />
                ))}
              </div>
            </div>
          )}

          {/* Category: Support Team */}
          {support.length > 0 && (
            <div className="flex flex-col gap-2">
              <div className="flex items-center gap-2 border-b border-tm-yellow/20 pb-0.5">
                <Zap className="w-3 h-3 text-tm-yellow" />
                <h3 className="text-[7px] lg:text-[8px] font-black tracking-[0.2em] uppercase text-tm-yellow">SUPPORT TEAM</h3>
              </div>
              <div className={`flex justify-center flex-wrap ${photoStyle === 'none' ? 'gap-10' : 'gap-6 sm:gap-12'}`}>
                {support.map((role, i) => (
                  <RoleItem key={role.id} role={role} index={i} />
                ))}
              </div>
            </div>
          )}

          {/* Category: Meeting Roles (Grid Gallery) */}
          {(standardRoles.length > 0 || remaining.length > 0) && (
            <div className="flex flex-col gap-2">
              <div className="flex items-center gap-2 border-b border-tm-yellow/20 pb-0.5">
                <MessageSquare className="w-3 h-3 text-tm-yellow" />
                <h3 className="text-[7px] lg:text-[8px] font-black tracking-[0.2em] uppercase text-tm-yellow">MEETING ROLES</h3>
              </div>
              <div className={`grid ${photoStyle === 'none' ? 'grid-cols-2 sm:grid-cols-3' : 'grid-cols-4 sm:grid-cols-5'} gap-y-4 gap-x-2 sm:gap-x-6 justify-items-center`}>
                {[...standardRoles, ...remaining].map((role, i) => (
                  <RoleItem key={role.id} role={role} index={i} />
                ))}
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="mt-4 pt-4 border-t border-tm-yellow/20">
          <div className="grid grid-cols-3 gap-1.5 bg-black/70 backdrop-blur-md rounded-2xl p-3 border border-white/10 shadow-2xl">
            <div className="flex flex-col items-center text-center gap-0.5">
              <Calendar className="w-4 h-4 text-tm-yellow" />
              <p className="text-[6px] uppercase text-tm-yellow font-black tracking-widest">DATE</p>
              <p className="text-[9px] sm:text-[11px] font-bold">
                {new Date(details.date).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
              </p>
            </div>
            <div className="flex flex-col items-center text-center gap-0.5 border-x border-tm-yellow/10">
              <Clock className="w-4 h-4 text-tm-yellow" />
              <p className="text-[6px] uppercase text-tm-yellow font-black tracking-widest">TIME</p>
              <p className="text-[9px] sm:text-[11px] font-bold">{details.time}</p>
            </div>
            <div className="flex flex-col items-center text-center gap-0.5">
              <MapPin className="w-4 h-4 text-tm-yellow" />
              <p className="text-[6px] uppercase text-tm-yellow font-black tracking-widest">VENUE</p>
              <p className="text-[9px] sm:text-[10px] font-bold leading-tight line-clamp-1">
                {details.location}
              </p>
            </div>
          </div>

          <div className="mt-4 text-center">
            <p className="text-[8px] text-tm-yellow opacity-70 uppercase font-black tracking-[0.6em]">WHERE LEADERS ARE MADE</p>
          </div>
        </div>
      </div>
    </div>
  );
};

