import React from 'react';
import { MapPin, Calendar, Clock, Award, Users, Shield, Zap, MessageSquare } from 'lucide-react';
import { RolePlayer, MeetingDetails } from '../types';

interface FlyerCanvasProps {
  details: MeetingDetails;
  roles: RolePlayer[];
  backgroundUrl: string | null;
  bgOpacity: number;
  photoStyle: 'circle' | 'square';
  layoutPattern?: 'standard' | 'staggered' | 'focus';
}

// Separate component for Role Items to avoid 'key' prop TS errors and unnecessary remounts
interface RoleItemProps {
  role: RolePlayer;
  photoStyle: 'circle' | 'square';
  layoutPattern: 'standard' | 'staggered' | 'focus';
  isFocused?: boolean;
  index?: number;
}

const RoleItem: React.FC<RoleItemProps> = ({ role, photoStyle, layoutPattern, isFocused = false, index = 0 }) => {
  const frameClass = photoStyle === 'circle' ? 'rounded-full' : 'rounded-xl';

  // Size consistency for alignment
  const sizeClasses = isFocused && layoutPattern === 'focus' 
    ? 'w-16 h-16 sm:w-20 sm:h-20 lg:w-24 lg:h-24' 
    : 'w-14 h-14 sm:w-16 sm:h-16 lg:w-18 lg:h-18';

  // Animation / Offset for staggered
  const staggeredClass = layoutPattern === 'staggered' && index % 2 !== 0 ? 'mt-4 sm:mt-6' : '';

  return (
    <div className={`flex flex-col items-center group animate-in fade-in zoom-in duration-300 ${staggeredClass} w-[80px] sm:w-[100px] lg:w-[110px]`}>
      <div className="relative mb-2 flex justify-center w-full">
        <div className={`${sizeClasses} ${frameClass} border-[3px] border-tm-yellow/40 overflow-hidden bg-tm-blue/40 shadow-xl group-hover:border-tm-yellow transition-all duration-300`}>
          {role.photoUrl ? (
            <img src={role.photoUrl} className="w-full h-full object-cover" alt={role.name} />
          ) : (
            <div className="w-full h-full flex items-center justify-center">
              <Users className="w-1/2 h-1/2 text-tm-yellow/10" />
            </div>
          )}
        </div>
      </div>
      <div className="text-center w-full px-1">
        <p className="text-[7px] sm:text-[8px] font-black text-tm-yellow uppercase tracking-tight leading-none mb-1.5 truncate drop-shadow-sm">
          {role.role}
        </p>
        <p className="text-[9px] sm:text-[11px] font-bold text-white leading-none drop-shadow-lg truncate">
          {role.name || "TBA"}
        </p>
      </div>
    </div>
  );
};

// Separate component for Category Sections
interface CategorySectionProps {
  title: string;
  icon: any;
  items: RolePlayer[];
  photoStyle: 'circle' | 'square';
  layoutPattern: 'standard' | 'staggered' | 'focus';
  isFocusedSection?: boolean;
}

const CategorySection: React.FC<CategorySectionProps> = ({ title, icon: Icon, items, photoStyle, layoutPattern, isFocusedSection = false }) => (
  items.length > 0 && (
    <div className="flex flex-col gap-2.5 w-full items-center">
      <div className="flex items-center gap-2 border-b border-tm-yellow/20 pb-1 w-full max-w-[90%] justify-center">
        <Icon className="w-3 h-3 text-tm-yellow shrink-0" />
        <h3 className="text-[7px] lg:text-[8px] font-black tracking-[0.3em] uppercase text-tm-yellow">{title}</h3>
      </div>
      <div className={`flex flex-wrap justify-center items-start w-full gap-x-2 sm:gap-x-4 lg:gap-x-6 gap-y-4`}>
        {items.map((role, i) => (
          <RoleItem 
            key={role.id} 
            role={role} 
            photoStyle={photoStyle} 
            layoutPattern={layoutPattern} 
            isFocused={isFocusedSection} 
            index={i} 
          />
        ))}
      </div>
    </div>
  )
);

const FlyerCanvas: React.FC<FlyerCanvasProps> = ({ 
  details, 
  roles, 
  backgroundUrl, 
  bgOpacity, 
  photoStyle, 
  layoutPattern = 'standard' 
}) => {
  // Categorization logic based on strict requested mapping
  const findRoles = (keywords: string[]) => 
    roles.filter(r => keywords.some(k => r.role.toUpperCase().includes(k.toUpperCase())));

  // Category 1: TMOD, TTM, General Evaluator
  const leadership = findRoles(['TMOD', 'TTM', 'GENERAL EVALUATOR', 'GE']).filter(r => !r.role.toUpperCase().match(/\d/)); 

  // Category 2: Timer, Ah Counter, Grammarian
  const support = findRoles(['TIMER', 'AH COUNTER', 'GRAMMARIAN']);

  // Category 3: Speaker, Evaluator
  const speakerEvaluator = findRoles(['SPEAKER', 'EVALUATOR']).filter(r => r.role.toUpperCase().match(/\d/) || !leadership.concat(support).some(l => l.id === r.id));

  const allCategorizedIds = new Set([...leadership, ...support, ...speakerEvaluator].map(r => r.id));
  const remaining = roles.filter(r => !allCategorizedIds.has(r.id) && (r.name || r.role));

  return (
    <div className="relative w-full h-full flex flex-col font-sans overflow-hidden bg-tm-blue">
