      </div>

      {/* Content Layer */}
      <div className="relative z-10 flex flex-col h-full text-white p-4 sm:p-6 lg:p-8 pt-6">
        <div className="absolute top-0 right-0 left-0 h-1.5 bg-tm-yellow shadow-md" />

        {/* Header */}
        <div className="mb-4 flex flex-col items-center text-center">
          <div className="flex items-center gap-2 mb-1.5 opacity-95">
            <Award className="w-5 h-5 text-tm-yellow" />
            <div className="flex flex-col text-left">
              <span className="text-[6px] lg:text-[7px] font-black tracking-[0.4em] uppercase text-tm-yellow leading-none">TOASTMASTERS INTERNATIONAL</span>
              <span className="text-[10px] lg:text-[13px] font-bold uppercase tracking-widest text-white leading-tight drop-shadow-md">{details.clubName}</span>
            </div>
          </div>

          <h1 className="text-xl sm:text-2xl lg:text-3xl font-header font-black mb-2 text-white drop-shadow-2xl leading-tight">
            {details.title.toUpperCase()}
          </h1>

          <div className="bg-tm-maroon/90 py-1 px-8 rounded-full border border-tm-yellow/30 mt-1 shadow-2xl">
            <p className="text-[9px] sm:text-[11px] lg:text-[12px] font-bold text-tm-yellow italic tracking-wide">
              Theme: {details.theme}
            </p>
          </div>
        </div>

        {/* Roles Section - Updated Groupings */}
        <div className="flex-1 flex flex-col gap-6 min-h-0 overflow-hidden py-2 no-scrollbar">
          <CategorySection 
            title="Leadership" 
            icon={Shield} 
            items={leadership} 
            photoStyle={photoStyle}
            layoutPattern={layoutPattern}
            isFocusedSection={true} 
          />

          <CategorySection 
            title="Support Team" 
            icon={Zap} 
            items={support} 
            photoStyle={photoStyle}
            layoutPattern={layoutPattern}
          />

          <CategorySection 
            title="Meeting Roles" 
            icon={MessageSquare} 
            items={[...speakerEvaluator, ...remaining]} 
            photoStyle={photoStyle}
            layoutPattern={layoutPattern}
          />
        </div>

        {/* Footer */}
        <div className="mt-4 pt-4 border-t border-tm-yellow/20">
          <div className="grid grid-cols-3 gap-2 bg-black/70 backdrop-blur-md rounded-2xl p-4 border border-white/10 shadow-2xl">
