              <p className="text-[9px] sm:text-[11px] font-bold">
                {new Date(details.date).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
              </p>
            </div>
            <div className="flex flex-col items-center text-center gap-1 border-x border-tm-yellow/10">
              <Clock className="w-4 h-4 text-tm-yellow" />
              <p className="text-[6px] uppercase text-tm-yellow font-black tracking-widest">TIME</p>
              <p className="text-[9px] sm:text-[11px] font-bold">{details.time}</p>
            </div>
            <div className="flex flex-col items-center text-center gap-1">
              <MapPin className="w-4 h-4 text-tm-yellow" />
              <p className="text-[6px] uppercase text-tm-yellow font-black tracking-widest">VENUE</p>
              <p className="text-[9px] sm:text-[10px] font-bold leading-tight line-clamp-1">
                {details.location}
              </p>
            </div>
          </div>

          <div className="mt-3 text-center">
            <p className="text-[8px] text-tm-yellow opacity-70 uppercase font-black tracking-[0.6em]">WHERE LEADERS ARE MADE</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default FlyerCanvas;

export interface RolePlayer {
  id: string;
  role: string;
  name: string;
  photoUrl: string | null;
}

export interface MeetingDetails {
  title: string;
  theme: string;
  date: string;
  time: string;
  location: string;
  clubName: string;
  flyerType: 'full' | 'spotlight';
}

export interface FlyerConfig {
  details: MeetingDetails;
  roles: RolePlayer[];
  backgroundUrl: string | null;
}

import React, { useState, useRef } from 'react';
import { Plus, Trash2, Camera, Download, Sparkles, Award, Printer, Image as ImageIcon, Loader2, Sliders, Layout, Square, Circle, UserCheck, CalendarDays } from 'lucide-react';
import { RolePlayer, MeetingDetails } from './types';
import { generateFlyerBackground, generateRoleAvatar } from './geminiService';
import FlyerCanvas from './components/FlyerCanvas';
import { toPng } from 'html-to-image';

const DEFAULT_ROLES = [
  "TMOD",
  "TTM",
  "General Evaluator",
  "Timer",
  "Ah Counter",
  "Grammarian",
  "Speaker 1",
  "Speaker 2",
  "Evaluator 1",
  "Evaluator 2"
];

const App: React.FC = () => {
  const flyerRef = useRef<HTMLDivElement>(null);
  const [details, setDetails] = useState<MeetingDetails>({
    title: "Meeting Invitation",
    theme: "The Art of Listening",
    date: new Date().toISOString().split('T')[0],
    time: "19:00",
    location: "Community Center / Zoom",
    clubName: "Your Club Name",
    flyerType: 'full'
  });

  const [roles, setRoles] = useState<RolePlayer[]>(
    DEFAULT_ROLES.map((role) => ({
      id: Math.random().toString(36).substr(2, 9),
      role,
      name: "",
      photoUrl: null
    }))
  );

  const [isGeneratingBg, setIsGeneratingBg] = useState(false);
  const [generatingIds, setGeneratingIds] = useState<Set<string>>(new Set());
  const [isDownloading, setIsDownloading] = useState(false);
  const [backgroundUrl, setBackgroundUrl] = useState<string | null>(null);
  const [bgOpacity, setBgOpacity] = useState(100);
  const [photoStyle, setPhotoStyle] = useState<'circle' | 'square'>('circle');

  const addRole = () => {
    setRoles([...roles, {
      id: Math.random().toString(36).substr(2, 9),
      role: "",
      name: "",
      photoUrl: null
    }]);
  };

  const removeRole = (id: string) => {
    setRoles(roles.filter(r => r.id !== id));
  };

  const updateRole = (id: string, updates: Partial<RolePlayer>) => {
    setRoles(roles.map(r => r.id === id ? { ...r, ...updates } : r));
  };

  const handlePhotoUpload = (id: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateRole(id, { photoUrl: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleMagicPhoto = async (id: string, roleName: string) => {
    setGeneratingIds(prev => new Set(prev).add(id));
    const url = await generateRoleAvatar(roleName || "Speaker", details.theme);
    if (url) {
      updateRole(id, { photoUrl: url });
    }
    setGeneratingIds(prev => {
      const next = new Set(prev);
      next.delete(id);
      return next;
    });
  };

  const handleGenerateBackground = async () => {
    setIsGeneratingBg(true);
    const url = await generateFlyerBackground(details.theme);
    if (url) {
      setBackgroundUrl(url);
    }
    setIsGeneratingBg(false);
  };

  const handlePrint = () => {
    window.print();
  };

  const handleDownloadImage = async () => {
    if (!flyerRef.current) return;
    setIsDownloading(true);
    try {
      const dataUrl = await toPng(flyerRef.current, { 
        quality: 1, 
        pixelRatio: 4, 
        cacheBust: true 
      });
      const link = document.createElement('a');
      link.download = `TM_Flyer_${details.theme.replace(/\s+/g, '_')}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      console.error('Failed to capture flyer image:', err);
      alert('Download failed. Try Print / Save PDF.');
    } finally {
      setIsDownloading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col lg:flex-row">
      {/* Editor Panel */}
      <div className="w-full lg:w-1/2 p-6 lg:p-10 overflow-y-auto no-print">
        <header className="mb-8">
          <div className="flex items-center gap-2 text-tm-maroon mb-2">
            <Award className="w-8 h-8" />
            <h1 className="text-2xl font-bold font-brand tracking-tight">Toastmasters Flyer Pro</h1>
          </div>
          <p className="text-slate-500 text-sm">Design professional meeting flyers with AI.</p>
        </header>

        <section className="space-y-6">
          {/* Meeting Details Card */}
          <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
            <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-4 border-b pb-2">Meeting Details</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-500 uppercase">Club Name</label>
                <input 
                  type="text" 
                  className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm"
                  value={details.clubName}
                  onChange={(e) => setDetails({ ...details, clubName: e.target.value })}
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-500 uppercase">Meeting Theme</label>
                <input 
                  type="text" 
                  className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm"
                  value={details.theme}
                  onChange={(e) => setDetails({ ...details, theme: e.target.value })}
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-500 uppercase">Date</label>
                <input type="date" className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm" value={details.date} onChange={(e) => setDetails({ ...details, date: e.target.value })} />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-500 uppercase">Time</label>
                <input type="time" className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm" value={details.time} onChange={(e) => setDetails({ ...details, time: e.target.value })} />
              </div>
              <div className="md:col-span-2 space-y-1">
                <label className="text-[10px] font-bold text-slate-500 uppercase">Location / Venue</label>
                <input type="text" className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm" value={details.location} onChange={(e) => setDetails({ ...details, location: e.target.value })} />
              </div>
            </div>
          </div>

          {/* Background & Layout Styles Card */}
          <div className="bg-tm-blue rounded-2xl p-6 shadow-lg text-white space-y-6">
            <div className="flex justify-between items-center">
              <div>
                <h2 className="text-lg font-bold flex items-center gap-2">
                  <Layout className="w-5 h-5 text-tm-yellow" />
                  Flyer Settings
                </h2>
                <p className="text-slate-300 text-xs">Control visual placement and styles.</p>
              </div>
              <button 
                onClick={handleGenerateBackground}
                disabled={isGeneratingBg}
                className="px-4 py-2 bg-white text-tm-blue rounded-full text-xs font-bold hover:bg-tm-yellow transition-all disabled:opacity-50"
              >
                {isGeneratingBg ? "Generating..." : "Magic Background"}
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-3">
                <div className="flex items-center justify-between text-xs font-bold text-tm-yellow uppercase tracking-widest">
                  <div className="flex items-center gap-2">
                    <Layout className="w-3.5 h-3.5" />
                    Flyer Template
                  </div>
                </div>
                <div className="flex bg-tm-blue/50 p-1 rounded-lg border border-white/10">
                  <button 
                    onClick={() => setDetails({ ...details, flyerType: 'full' })}
                    className={`flex-1 flex items-center justify-center gap-2 py-1.5 rounded-md text-[10px] font-bold transition-all ${details.flyerType === 'full' ? 'bg-tm-yellow text-tm-blue shadow-sm' : 'hover:bg-white/5'}`}
                  >
                    <CalendarDays className="w-3 h-3" />
                    Full Meeting
                  </button>
                  <button 
                    onClick={() => setDetails({ ...details, flyerType: 'spotlight' })}
                    className={`flex-1 flex items-center justify-center gap-2 py-1.5 rounded-md text-[10px] font-bold transition-all ${details.flyerType === 'spotlight' ? 'bg-tm-yellow text-tm-blue shadow-sm' : 'hover:bg-white/5'}`}
                  >
                    <UserCheck className="w-3 h-3" />
                    Spotlight
                  </button>
                </div>
              </div>

              <div className="space-y-3">
                <div className="flex items-center justify-between text-xs font-bold text-tm-yellow uppercase tracking-widest">
                  <div className="flex items-center gap-2">
                    <ImageIcon className="w-3.5 h-3.5" />
                    Photo Frame Style
                  </div>
                </div>
                <div className="flex bg-tm-blue/50 p-1 rounded-lg border border-white/10">
                  <button 
                    onClick={() => setPhotoStyle('circle')}
                    className={`flex-1 flex items-center justify-center gap-2 py-1.5 rounded-md text-[10px] font-bold transition-all ${photoStyle === 'circle' ? 'bg-tm-yellow text-tm-blue shadow-sm' : 'hover:bg-white/5'}`}
                  >
                    <Circle className="w-3 h-3" />
                    Circle
                  </button>
                  <button 
                    onClick={() => setPhotoStyle('square')}
                    className={`flex-1 flex items-center justify-center gap-2 py-1.5 rounded-md text-[10px] font-bold transition-all ${photoStyle === 'square' ? 'bg-tm-yellow text-tm-blue shadow-sm' : 'hover:bg-white/5'}`}
                  >
                    <Square className="w-3 h-3" />
                    Square
                  </button>
                </div>
              </div>

              <div className="md:col-span-2 space-y-3">
                <div className="flex items-center justify-between text-xs font-bold text-tm-yellow uppercase tracking-widest">
                  <div className="flex items-center gap-2">
                    <Sliders className="w-3.5 h-3.5" />
                    Background Opacity
                  </div>
                  <span>{bgOpacity}%</span>
                </div>
                <input 
                  type="range" 
                  min="0" 
                  max="100" 
                  value={bgOpacity} 
                  onChange={(e) => setBgOpacity(parseInt(e.target.value))}
                  className="w-full h-1.5 bg-tm-blue/50 rounded-lg appearance-none cursor-pointer accent-tm-yellow"
                />
              </div>
            </div>
          </div>

          {/* Roles Management */}
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <div className="flex flex-col">
                <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">Role Players</h2>
                <p className="text-[10px] text-slate-400">
                  {details.flyerType === 'full' 
                    ? "Add names for the full agenda." 
                    : "Add Speakers and Evaluators for the spotlight flyer."}
                </p>
              </div>
              <div className="flex gap-2">
                <button onClick={addRole} className="p-2 bg-white text-tm-maroon rounded-full border border-slate-100 hover:bg-slate-50 shadow-sm"><Plus className="w-5 h-5" /></button>
              </div>
            </div>

            <div className="grid grid-cols-1 gap-3">
              {roles.map((role) => (
                <div key={role.id} className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm flex items-start gap-4 group transition-all hover:border-tm-maroon/20">
                  <div className="relative">
                    <div className="w-14 h-14 rounded-full bg-slate-50 border-2 border-slate-100 flex items-center justify-center overflow-hidden">
                      {generatingIds.has(role.id) ? (
                        <Loader2 className="w-5 h-5 text-tm-blue animate-spin" />
                      ) : role.photoUrl ? (
                        <img src={role.photoUrl} className="w-full h-full object-cover" />
                      ) : (
                        <Camera className="w-5 h-5 text-slate-300" />
                      )}
                    </div>
                    <div className="absolute -bottom-1 -right-1 flex flex-col gap-1">
                      <label className="p-1.5 bg-tm-blue text-white rounded-full cursor-pointer shadow-md hover:bg-tm-blue/90 border border-white">
                        <Plus className="w-3 h-3" />
                        <input type="file" className="hidden" accept="image/*" onChange={(e) => handlePhotoUpload(role.id, e)} />
                      </label>
                      <button 
                        onClick={() => handleMagicPhoto(role.id, role.role)}
                        disabled={generatingIds.has(role.id)}
                        className="p-1.5 bg-tm-yellow text-tm-blue rounded-full shadow-md hover:scale-110 transition-all border border-white"
                        title="AI Magic Photo"
                      >
                        <Sparkles className="w-3 h-3" />
                      </button>
                    </div>
                  </div>

                  <div className="flex-1 grid grid-cols-2 gap-2">
                    <div className="space-y-1">
                      <input 
                        className="w-full text-[10px] font-bold text-tm-blue border-none bg-transparent focus:ring-0 p-0 uppercase"
                        value={role.role}
                        onChange={(e) => updateRole(role.id, { role: e.target.value })}
                        placeholder="Role (e.g. Speaker 1)"
                      />
                      <input 
                        className="w-full text-xs font-semibold text-slate-800 border-none bg-transparent focus:ring-0 p-0"
                        value={role.name}
                        onChange={(e) => updateRole(role.id, { name: e.target.value })}
                        placeholder="Player Name"
                      />
                    </div>
                    <div className="flex justify-end items-center">
                      <button onClick={() => removeRole(role.id)} className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"><Trash2 className="w-4 h-4" /></button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </section>
      </div>

      {/* Preview Panel */}
      <div className="w-full lg:w-1/2 bg-slate-200 flex flex-col items-center justify-center p-4 lg:p-10 sticky top-0 print:p-0 print:bg-white print:static print:w-full print:h-screen">
        <div className="mb-6 flex gap-3 no-print z-50">
          <button onClick={handleDownloadImage} disabled={isDownloading} className="flex items-center gap-2 px-6 py-3 bg-tm-blue text-white rounded-xl font-bold hover:shadow-xl transition-all shadow-lg active:scale-95 disabled:opacity-50 cursor-pointer">
            <ImageIcon className="w-5 h-5" />
            <span>{isDownloading ? '...' : 'PNG'}</span>
          </button>
          <button onClick={handlePrint} className="flex items-center gap-2 px-6 py-3 bg-tm-maroon text-white rounded-xl font-bold hover:shadow-xl transition-all shadow-lg active:scale-95 cursor-pointer">
            <Printer className="w-5 h-5" />
            <span>PDF</span>
          </button>
        </div>

        <div id="flyer-preview-container" ref={flyerRef} className="w-full max-w-[500px] shadow-2xl bg-tm-blue aspect-[3/4] relative print:shadow-none print:max-w-none">
          <FlyerCanvas details={details} roles={roles} backgroundUrl={backgroundUrl} bgOpacity={bgOpacity} photoStyle={photoStyle} />
        </div>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { MapPin, Calendar, Clock, Award, Users, Shield, Zap, MessageSquare, UserCheck, Star } from 'lucide-react';
import { RolePlayer, MeetingDetails } from '../types';

interface FlyerCanvasProps {
  details: MeetingDetails;
  roles: RolePlayer[];
  backgroundUrl: string | null;
  bgOpacity: number;
  photoStyle: 'circle' | 'square';
  layoutPattern?: 'standard' | 'staggered' | 'focus';
}

interface RoleItemProps {
  role: RolePlayer;
  photoStyle: 'circle' | 'square';
  layoutPattern: 'standard' | 'staggered' | 'focus';
  isFocused?: boolean;
  index?: number;
  variant?: 'normal' | 'large';
}

const RoleItem: React.FC<RoleItemProps> = ({ role, photoStyle, layoutPattern, isFocused = false, index = 0, variant = 'normal' }) => {
  const frameClass = photoStyle === 'circle' ? 'rounded-full' : 'rounded-2xl';

  const sizeClasses = variant === 'large'
    ? 'w-24 h-24 sm:w-32 sm:h-32 lg:w-40 lg:h-40'
    : isFocused && layoutPattern === 'focus' 
      ? 'w-16 h-16 sm:w-20 sm:h-20 lg:w-24 lg:h-24' 
      : 'w-14 h-14 sm:w-16 sm:h-16 lg:w-18 lg:h-18';

  const staggeredClass = layoutPattern === 'staggered' && index % 2 !== 0 ? 'mt-4 sm:mt-6' : '';

  return (
    <div className={`flex flex-col items-center group animate-in fade-in zoom-in duration-300 ${staggeredClass} ${variant === 'large' ? 'w-[140px] sm:w-[180px] lg:w-[220px]' : 'w-[80px] sm:w-[100px] lg:w-[110px]'}`}>
      <div className="relative mb-2 flex justify-center w-full">
        <div className={`${sizeClasses} ${frameClass} border-[4px] border-tm-yellow/40 overflow-hidden bg-tm-blue/40 shadow-2xl group-hover:border-tm-yellow transition-all duration-300`}>
          {role.photoUrl ? (
            <img src={role.photoUrl} className="w-full h-full object-cover" alt={role.name} />
          ) : (
            <div className="w-full h-full flex items-center justify-center">
              <Users className="w-1/2 h-1/2 text-tm-yellow/10" />
            </div>
          )}
        </div>
        {variant === 'large' && (
          <div className="absolute -top-2 -right-2 bg-tm-maroon p-2 rounded-full border-2 border-tm-yellow shadow-lg">
            <Star className="w-4 h-4 text-tm-yellow fill-tm-yellow" />
          </div>
        )}
      </div>
      <div className="text-center w-full px-1">
        <p className={`${variant === 'large' ? 'text-[9px] sm:text-[11px]' : 'text-[7px] sm:text-[8px]'} font-black text-tm-yellow uppercase tracking-widest leading-none mb-2 truncate drop-shadow-sm`}>
          {role.role}
        </p>
        <p className={`${variant === 'large' ? 'text-[12px] sm:text-[16px]' : 'text-[9px] sm:text-[11px]'} font-bold text-white leading-tight drop-shadow-lg truncate`}>
          {role.name || "To Be Announced"}
        </p>
      </div>
    </div>
  );
};

const CategorySection: React.FC<{ 
  title: string; 
  icon: any; 
  items: RolePlayer[]; 
  photoStyle: 'circle' | 'square'; 
  layoutPattern: 'standard' | 'staggered' | 'focus'; 
  isFocusedSection?: boolean 
}> = ({ title, icon: Icon, items, photoStyle, layoutPattern, isFocusedSection = false }) => (
  items.length > 0 && (
    <div className="flex flex-col gap-2.5 w-full items-center">
      <div className="flex items-center gap-2 border-b border-tm-yellow/20 pb-1 w-full max-w-[90%] justify-center">
        <Icon className="w-3 h-3 text-tm-yellow shrink-0" />
        <h3 className="text-[7px] lg:text-[8px] font-black tracking-[0.3em] uppercase text-tm-yellow">{title}</h3>
      </div>
      <div className={`flex flex-wrap justify-center items-start w-full gap-x-2 sm:gap-x-4 lg:gap-x-6 gap-y-4`}>
        {items.map((role, i) => (
          <RoleItem 
            key={role.id} 
            role={role} 
            photoStyle={photoStyle} 
            layoutPattern={layoutPattern} 
            isFocused={isFocusedSection} 
            index={i} 
          />
        ))}
      </div>
    </div>
  )
);

const FlyerCanvas: React.FC<FlyerCanvasProps> = ({ 
  details, 
  roles, 
  backgroundUrl, 
  bgOpacity, 
  photoStyle, 
  layoutPattern = 'standard' 
}) => {
  const findRoles = (keywords: string[]) => 
    roles.filter(r => keywords.some(k => r.role.toUpperCase().includes(k.toUpperCase())));

  // Shared categorization
  const leadership = findRoles(['TMOD', 'TTM', 'GENERAL EVALUATOR', 'GE']).filter(r => !r.role.toUpperCase().match(/\d/)); 
  const support = findRoles(['TIMER', 'AH COUNTER', 'GRAMMARIAN']);
  const speakers = findRoles(['SPEAKER']);
  const evaluators = findRoles(['EVALUATOR']);

  const speakerEvaluator = [...speakers, ...evaluators];
  const allCategorizedIds = new Set([...leadership, ...support, ...speakerEvaluator].map(r => r.id));
  const remaining = roles.filter(r => !allCategorizedIds.has(r.id) && (r.name || r.role));

  const renderFullMeeting = () => (
    <div className="flex-1 flex flex-col gap-6 min-h-0 overflow-hidden py-2 no-scrollbar">
      <CategorySection 
        title="Leadership" 
        icon={Shield} 
        items={leadership} 
        photoStyle={photoStyle}
        layoutPattern={layoutPattern}
        isFocusedSection={true} 
      />
      <CategorySection 
        title="Support Team" 
        icon={Zap} 
        items={support} 
        photoStyle={photoStyle}
        layoutPattern={layoutPattern}
      />
      <CategorySection 
        title="Meeting Roles" 
        icon={MessageSquare} 
        items={[...speakerEvaluator, ...remaining]} 
        photoStyle={photoStyle}
        layoutPattern={layoutPattern}
      />
    </div>
  );

  const renderSpotlight = () => {
    // Group speakers and evaluators into pairs if possible (Speaker 1 with Evaluator 1)
    const pairs: Array<{ speaker?: RolePlayer, evaluator?: RolePlayer }> = [];
    const maxIndex = Math.max(speakers.length, evaluators.length);

    for (let i = 0; i < maxIndex; i++) {
      pairs.push({
        speaker: speakers[i],
        evaluator: evaluators[i]
      });
    }

    return (
      <div className="flex-1 flex flex-col gap-10 min-h-0 overflow-hidden py-6 items-center justify-center">
        {pairs.length === 0 ? (
          <div className="flex flex-col items-center gap-4 text-white/40">
            <UserCheck className="w-16 h-16" />
            <p className="font-bold text-sm tracking-widest uppercase">Add Speakers & Evaluators</p>
          </div>
        ) : (
          <div className="w-full flex flex-col gap-12 overflow-y-auto no-scrollbar items-center">
            {pairs.map((pair, idx) => (
              <div key={idx} className="flex flex-col items-center gap-6 w-full animate-in slide-in-from-bottom duration-500" style={{ animationDelay: `${idx * 150}ms` }}>
                <div className="flex items-center gap-4 w-full justify-center">
                  <div className="h-px bg-tm-yellow/20 flex-1" />
                  <span className="text-[10px] font-black text-tm-yellow tracking-[0.4em] uppercase">Session {idx + 1}</span>
                  <div className="h-px bg-tm-yellow/20 flex-1" />
                </div>
                <div className="flex items-start justify-center gap-8 sm:gap-16">
                  {pair.speaker && (
                    <RoleItem 
                      role={pair.speaker} 
                      photoStyle={photoStyle} 
                      layoutPattern="standard" 
                      variant="large" 
                    />
                  )}
                  {pair.evaluator && (
                    <RoleItem 
                      role={pair.evaluator} 
                      photoStyle={photoStyle} 
                      layoutPattern="standard" 
                      variant="large" 
                    />
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="relative w-full h-full flex flex-col font-sans overflow-hidden bg-tm-blue">
      {/* Background Layer with Opacity Control */}
      <div className="absolute inset-0 z-0">
        {backgroundUrl ? (
          <img 
