    // Strictly limit to 2 speakers and 2 evaluators as requested (4 photo frames total)
    const pairs = [
      { 
        speaker: speakers.find(s => s.role.includes('1')) || speakers[0], 
        evaluator: evaluators.find(e => e.role.includes('1')) || evaluators[0] 
