          <div className={`grid grid-cols-3 gap-1 ${isLightBackground ? 'bg-white/80' : 'bg-black/70'} backdrop-blur-md rounded-xl p-3 border ${isLightBackground ? 'border-tm-blue/10' : 'border-white/10'} shadow-xl`}>
