                      <div className={`w-16 h-16 ${photoStyle === 'circle' ? 'rounded-full' : 'rounded-2xl'} bg-slate-50 border-2 border-slate-100 flex items-center justify-center overflow-hidden`}>
                        {generatingIds.has(role.id) ? <Loader2 className="w-5 h-5 text-tm-blue animate-spin" /> : role.photoUrl ? <img src={role.photoUrl} className="w-full h-full object-cover" /> : <Camera className="w-5 h-5 text-slate-300" />}
