                      <input className="w-full text-sm font-bold text-slate-800 border-none bg-transparent p-0" value={role.name} onChange={(e) => updateRole(role.id, { name: e.target.value })} placeholder="Member Name" />
                    </div>
                    <button onClick={() => removeRole(role.id)} className="p-3 text-slate-200 hover:text-red-500 transition-all"><Trash2 className="w-5 h-5" /></button>
