interface RoleItemProps {
  role?: RolePlayer;
  photoStyle: 'circle' | 'square';
  layoutPattern: 'standard' | 'staggered' | 'focus';
  isFocused?: boolean;
  index?: number;
  variant?: 'normal' | 'large';
