  isLightBackground: boolean;
  globalScale?: number;
}

const RoleItem: React.FC<RoleItemProps> = ({ 
  role, 
  photoStyle, 
  layoutPattern, 
  isFocused = false, 
  index = 0, 
  variant = 'normal', 
