  { id: 'maroon', hex: '#772432', label: 'True Maroon' },
  { id: 'midnight', hex: '#0F172A', label: 'Midnight' },
  { id: 'royal', hex: 'linear-gradient(135deg, #004165, #772432)', label: 'Royal Duo' },
  { id: 'sunset', hex: 'linear-gradient(135deg, #772432, #F2DF74)', label: 'Sunset Mix' },
  { id: 'ocean', hex: 'linear-gradient(135deg, #004165, #0F172A)', label: 'Deep Ocean' },
  { id: 'platinum', hex: 'linear-gradient(135deg, #004165, #A9B2B1)', label: 'Platinum' },
  { id: 'grey', hex: '#A9B2B1', label: 'Cool Grey' },
  { id: 'yellow', hex: '#F2DF74', label: 'Happy Yellow' },
] as const;

const App: React.FC = () => {
  const flyerRef = useRef<HTMLDivElement>(null);
  const [details, setDetails] = useState<MeetingDetails>({
    title: "MEETING INVITATION",
    theme: "The Art of Listening",
    themeLabel: "Theme:",
    leadershipLabel: "Leadership",
    supportLabel: "Support Roles",
    date: new Date().toISOString().split('T')[0],
    time: "19:00",
    location: "Community Center / Zoom",
    clubName: "Your Club Name",
    flyerType: 'full',
    themeColor: 'blue',
    globalPhotoScale: 1.0,
    titleFont: 'sans',
    badgeShape: 'capsule'
  });

  const createDefaultRoles = (type: 'full' | 'spotlight'): RolePlayer[] => {
    const rolesList = type === 'full' ? FULL_MEETING_ROLES : SPOTLIGHT_ROLES;
    return rolesList.map((role) => ({
      id: Math.random().toString(36).substr(2, 9),
      role,
      name: "",
      photoUrl: null,
      scale: 1.0
    }));
  };

  const [roles, setRoles] = useState<RolePlayer[]>(createDefaultRoles('full'));
  const [isGeneratingBg, setIsGeneratingBg] = useState(false);
  const [generatingIds, setGeneratingIds] = useState<Set<string>>(new Set());
  const [isDownloading, setIsDownloading] = useState(false);
  const [backgroundUrl, setBackgroundUrl] = useState<string | null>(null);
  const [bgOpacity, setBgOpacity] = useState(100);
  const [photoStyle, setPhotoStyle] = useState<'circle' | 'square'>('circle');
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const handleFlyerTypeChange = (type: 'full' | 'spotlight') => {
    if (details.flyerType === type) return;
    setDetails(prev => ({ ...prev, flyerType: type }));
    setRoles(createDefaultRoles(type));
  };

  const addRole = () => {
    const newRoleName = details.flyerType === 'spotlight' ? "Spotlight Member" : "Additional Role";
    setRoles([...roles, {
      id: Math.random().toString(36).substr(2, 9),
      role: newRoleName,
      name: "",
      photoUrl: null,
      scale: 1.0
    }]);
  };

  const removeRole = (id: string) => {
    setRoles(roles.filter(r => r.id !== id));
  };

  const updateRole = (id: string, updates: Partial<RolePlayer>) => {
    setRoles(roles.map(r => r.id === id ? { ...r, ...updates } : r));
  };

  const handlePhotoUpload = (id: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateRole(id, { photoUrl: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleError = (err: any) => {
    console.error("API Error:", err);
    setErrorMsg(err.message || "An unexpected error occurred. Please ensure your API key is active.");
  };

  const handleMagicPhoto = async (id: string, roleName: string) => {
    setErrorMsg(null);
    setGeneratingIds(prev => new Set(prev).add(id));
    try {
      const url = await generateRoleAvatar(roleName || "Speaker", details.theme);
      if (url) {
        updateRole(id, { photoUrl: url });
      } else {
        setErrorMsg("Avatar generation failed. Please try again.");
      }
    } catch (err: any) {
      handleError(err);
    } finally {
      setGeneratingIds(prev => {
        const next = new Set(prev);
        next.delete(id);
        return next;
      });
    }
  };

  const handleGenerateBackground = async () => {
    if (isGeneratingBg) return;
    setErrorMsg(null);
    setIsGeneratingBg(true);
    try {
      const url = await generateFlyerBackground(details.theme);
      if (url) {
        setBackgroundUrl(url);
        setBgOpacity(100);
      } else {
        setErrorMsg("Background generation returned no image.");
      }
    } catch (err: any) {
      handleError(err);
    } finally {
      setIsGeneratingBg(false);
    }
  };

  const handleDownloadImage = async () => {
    if (!flyerRef.current || isDownloading) return;
    setIsDownloading(true);
    try {
      const dataUrl = await toPng(flyerRef.current, { 
        quality: 1, 
        pixelRatio: 4, 
        cacheBust: true 
      });
      const link = document.createElement('a');
      link.download = `TM_Flyer_${details.theme.replace(/\s+/g, '_')}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      console.error('Download error:', err);
      setErrorMsg('Failed to export flyer. Please try again.');
    } finally {
      setIsDownloading(false);
    }
  };

  const inputClasses = "w-full px-4 py-2.5 bg-white/50 border border-slate-200 rounded-xl text-sm text-slate-900 placeholder:text-slate-400 focus:border-tm-blue focus:ring-4 focus:ring-tm-blue/10 outline-none transition-all duration-200";

  return (
    <div className="min-h-screen bg-[#F8FAFC] flex flex-col lg:flex-row font-sans text-slate-900">
      {errorMsg && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[110] animate-in slide-in-from-top-4 duration-300">
          <div className="bg-red-50 border border-red-200 text-red-700 px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-4 min-w-[320px]">
            <AlertCircle className="w-6 h-6 shrink-0" />
            <div className="flex-1 text-sm font-semibold">{errorMsg}</div>
            <button onClick={() => setErrorMsg(null)} className="p-1 hover:bg-red-100 rounded-lg transition-colors">
              <X className="w-4 h-4" />
            </button>
          </div>
        </div>
      )}

      <div className="w-full lg:w-[45%] p-6 lg:p-12 overflow-y-auto no-print scroll-smooth">
        <header className="mb-10 animate-in fade-in slide-in-from-top-4 duration-700">
          <div className="flex items-center gap-4 mb-4">
            <div className="p-3 bg-gradient-to-br from-tm-maroon to-tm-blue rounded-2xl shadow-lg shadow-tm-maroon/20 animate-float">
              <Rocket className="w-8 h-8 text-white" />
            </div>
            <div>
              <h1 className="text-3xl font-black tracking-tight font-header shimmer-text">Flyer Pro</h1>
              <div className="flex items-center gap-2">
                <span className="h-1 w-8 bg-tm-maroon rounded-full"></span>
                <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Advanced Designer</p>
              </div>
            </div>
          </div>
        </header>

        <div className="space-y-8 stagger-in">
          <section className="glass-card rounded-[2rem] p-8 shadow-xl shadow-slate-200/50 border border-white/60">
            <div className="flex items-center gap-3 mb-6">
              <div className="w-8 h-8 rounded-lg bg-tm-blue/10 flex items-center justify-center">
                <CalendarDays className="w-4 h-4 text-tm-blue" />
              </div>
              <h2 className="text-base font-black text-slate-800 uppercase tracking-widest">Meeting Details</h2>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
              <div className="md:col-span-2 space-y-1.5 text-left">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider ml-1">Flyer Title (Heading)</label>
                <input type="text" className={inputClasses} value={details.title} placeholder="e.g. MEETING INVITATION" onChange={(e) => setDetails({ ...details, title: e.target.value.toUpperCase() })} />
              </div>
              <div className="space-y-1.5 text-left">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider ml-1">Club Identity</label>
                <input type="text" className={inputClasses} value={details.clubName} placeholder="e.g. Skyline Speakers" onChange={(e) => setDetails({ ...details, clubName: e.target.value })} />
              </div>
              <div className="space-y-1.5 text-left">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider ml-1">Meeting Theme</label>
                <input type="text" className={inputClasses} value={details.theme} placeholder="e.g. Overcoming Fear" onChange={(e) => setDetails({ ...details, theme: e.target.value })} />
              </div>
              <div className="space-y-1.5 text-left">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider ml-1">Theme Label Prefix</label>
                <input type="text" className={inputClasses} value={details.themeLabel} placeholder="e.g. Theme: or Topic:" onChange={(e) => setDetails({ ...details, themeLabel: e.target.value })} />
              </div>
              <div className="space-y-1.5 text-left">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider ml-1">Leadership Section Title</label>
                <input type="text" className={inputClasses} value={details.leadershipLabel} placeholder="e.g. Leadership" onChange={(e) => setDetails({ ...details, leadershipLabel: e.target.value })} />
              </div>
              <div className="space-y-1.5 text-left">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider ml-1">Support Section Title</label>
                <input type="text" className={inputClasses} value={details.supportLabel} placeholder="e.g. Support Roles" onChange={(e) => setDetails({ ...details, supportLabel: e.target.value })} />
              </div>
              <div className="space-y-1.5 text-left">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider ml-1">Event Date</label>
                <input type="date" className={inputClasses} value={details.date} onChange={(e) => setDetails({ ...details, date: e.target.value })} />
              </div>
              <div className="space-y-1.5 text-left">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider ml-1">Start Time</label>
                <input type="time" className={inputClasses} value={details.time} onChange={(e) => setDetails({ ...details, time: e.target.value })} />
              </div>
              <div className="md:col-span-2 space-y-1.5 text-left">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider ml-1">Location / Link</label>
                <textarea rows={2} className={`${inputClasses} resize-none text-sm`} value={details.location} onChange={(e) => setDetails({ ...details, location: e.target.value })} />
              </div>
            </div>
          </section>

          <section className="bg-tm-blue rounded-[2.5rem] p-8 shadow-2xl shadow-tm-blue/30 text-white relative overflow-hidden">
            <div className="relative z-10 space-y-8">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                <div className="shrink-0 text-left">
                  <h2 className="text-xl font-black flex items-center gap-3">
                    <Palette className="w-6 h-6 text-tm-yellow" />
                    Studio Style
                  </h2>
                </div>
                <button onClick={handleGenerateBackground} disabled={isGeneratingBg} className="group min-w-max px-8 py-4 bg-white text-tm-blue rounded-full text-xs font-black uppercase tracking-widest hover:bg-tm-yellow transition-all duration-300 disabled:opacity-50 flex items-center justify-center gap-4 shadow-xl">
                  {isGeneratingBg ? <Loader2 className="w-4 h-4 animate-spin shrink-0" /> : <Sparkles className="w-4 h-4 shrink-0" />}
                  <span>AI Magic BG</span>
                </button>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="md:col-span-2 space-y-4 text-left">
                  <div className="flex items-center gap-2 text-[10px] font-black text-tm-yellow uppercase tracking-widest">
                    <Award className="w-3.5 h-3.5" />
                    Brand Palette
                  </div>
                  <div className="grid grid-cols-3 sm:grid-cols-5 gap-3">
                    {BRAND_COLORS.map((color) => (
                      <button key={color.id} onClick={() => setDetails(prev => ({ ...prev, themeColor: color.id as any }))} className={`group relative h-12 rounded-2xl border-2 transition-all duration-300 ${details.themeColor === color.id ? 'border-tm-yellow scale-105 shadow-lg' : 'border-white/10'}`} style={{ background: color.hex }}>
                        {details.themeColor === color.id && <div className="absolute inset-0 flex items-center justify-center bg-black/10"><Check className="w-5 h-5 text-tm-yellow" /></div>}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="space-y-4 text-left">
                  <div className="flex items-center gap-2 text-[10px] font-black text-tm-yellow uppercase tracking-widest">
                    <Type className="w-3.5 h-3.5" />
                    Title Font
                  </div>
                  <div className="flex bg-white/10 p-1.5 rounded-2xl border border-white/5">
                    <button onClick={() => setDetails(prev => ({ ...prev, titleFont: 'sans' }))} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-wider transition-all ${details.titleFont === 'sans' ? 'bg-white text-tm-blue' : 'hover:bg-white/5'}`}>Modern Sans</button>
                    <button onClick={() => setDetails(prev => ({ ...prev, titleFont: 'serif' }))} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-wider transition-all ${details.titleFont === 'serif' ? 'bg-white text-tm-blue' : 'hover:bg-white/5'}`}>Elegant Serif</button>
                  </div>
                </div>

                <div className="space-y-4 text-left">
                  <div className="flex items-center gap-2 text-[10px] font-black text-tm-yellow uppercase tracking-widest">
                    <Shapes className="w-3.5 h-3.5" />
                    Badge Shape
                  </div>
                  <div className="flex bg-white/10 p-1.5 rounded-2xl border border-white/5">
                    <button onClick={() => setDetails(prev => ({ ...prev, badgeShape: 'capsule' }))} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-wider transition-all ${details.badgeShape === 'capsule' ? 'bg-white text-tm-blue' : 'hover:bg-white/5'}`}>Capsule</button>
                    <button onClick={() => setDetails(prev => ({ ...prev, badgeShape: 'modern' }))} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-wider transition-all ${details.badgeShape === 'modern' ? 'bg-white text-tm-blue' : 'hover:bg-white/5'}`}>Sharp</button>
                  </div>
                </div>

                <div className="md:col-span-2 space-y-4 text-left">
                  <div className="flex items-center justify-between text-[10px] font-black text-tm-yellow uppercase tracking-widest">
                    <div className="flex items-center gap-2"><Layers className="w-3.5 h-3.5" />Background Blend</div>
                    <span className="bg-white/20 px-2 py-0.5 rounded-md font-mono text-[9px]">{bgOpacity}%</span>
                  </div>
                  <input type="range" min="0" max="100" step="5" value={bgOpacity} onChange={(e) => setBgOpacity(parseInt(e.target.value))} className="w-full h-2 bg-white/20 rounded-full appearance-none cursor-pointer accent-tm-yellow" />
                </div>

                <div className="md:col-span-2 space-y-4 text-left">
                  <div className="flex items-center justify-between text-[10px] font-black text-tm-yellow uppercase tracking-widest">
                    <div className="flex items-center gap-2"><Maximize2 className="w-3.5 h-3.5" />Global Frame Scale</div>
                    <span className="bg-white/20 px-2 py-0.5 rounded-md font-mono text-[9px]">{details.globalPhotoScale?.toFixed(1)}x</span>
                  </div>
                  <input type="range" min="0.5" max="2.0" step="0.1" value={details.globalPhotoScale} onChange={(e) => setDetails({ ...details, globalPhotoScale: parseFloat(e.target.value) })} className="w-full h-2 bg-white/20 rounded-full appearance-none cursor-pointer accent-tm-yellow" />
                </div>
              </div>
            </div>
          </section>

          <section className="space-y-6">
            <div className="flex justify-between items-end px-2">
              <h2 className="text-base font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
                <UserCheck className="w-5 h-5 text-tm-maroon" />
                Role Players
              </h2>
              <button onClick={addRole} className="flex items-center gap-2 px-5 py-2.5 bg-tm-maroon text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-tm-maroon/90 shadow-xl transition-all">
                <Plus className="w-3 h-3" />
                Add Member
              </button>
            </div>
            <div className="grid grid-cols-1 gap-4">
              {roles.map((role) => (
                <div key={role.id} className="group bg-white p-5 rounded-3xl border border-slate-100 shadow-sm flex flex-col gap-4 focus-within:shadow-xl transition-all duration-300">
                  <div className="flex items-center gap-6">
                    <div className="relative shrink-0">
                      <div className={`w-16 h-16 ${photoStyle === 'circle' ? 'rounded-full' : 'rounded-2xl'} bg-slate-50 border-2 border-slate-100 flex items-center justify-center overflow-hidden transition-all group-hover:border-tm-maroon/30`}>
                        {generatingIds.has(role.id) ? (
                          <Loader2 className="w-5 h-5 text-tm-blue animate-spin" />
                        ) : role.photoUrl ? (
                          <img src={role.photoUrl} className="w-full h-full object-cover" />
                        ) : (
                          <Camera className="w-5 h-5 text-slate-300" />
                        )}
                      </div>
                      <div className="absolute -bottom-1 -right-1 flex flex-col gap-1.5 opacity-0 group-hover:opacity-100 focus-within:opacity-100 transition-all duration-300 z-20">
                        <label className="p-2 bg-tm-blue text-white rounded-full cursor-pointer shadow-xl hover:scale-110 active:scale-95 transition-all">
                          <Plus className="w-3 h-3" />
                          <input type="file" className="hidden" accept="image/*" onChange={(e) => handlePhotoUpload(role.id, e)} />
                        </label>
                        <button onClick={() => handleMagicPhoto(role.id, role.role)} className="p-2 bg-tm-yellow text-tm-blue rounded-full shadow-xl hover:scale-110 active:scale-95 transition-all">
                          <Sparkles className="w-3 h-3" />
                        </button>
                      </div>
                    </div>
                    <div className="flex-1 text-left space-y-1">
                      <input 
                        className="w-full text-[9px] font-black text-tm-maroon border-none bg-transparent p-0 uppercase tracking-widest focus:ring-0 placeholder:text-tm-maroon/30" 
                        value={role.role} 
                        onChange={(e) => updateRole(role.id, { role: e.target.value })} 
                        placeholder="Role Name"
                      />
                      <input 
                        className="w-full text-sm font-bold text-slate-800 border-none bg-transparent p-0 focus:ring-0 placeholder:text-slate-300" 
                        value={role.name} 
                        onChange={(e) => updateRole(role.id, { name: e.target.value })} 
                        placeholder="Member Name" 
                      />
                    </div>
                    <button onClick={() => removeRole(role.id)} className="p-3 text-slate-200 hover:text-red-500 transition-all">
                      <Trash2 className="w-5 h-5" />
                    </button>
                  </div>
                  <div className="flex items-center gap-4 px-1 pt-2 border-t border-slate-50">
                    <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest whitespace-nowrap">Local Scale</span>
                    <input 
                      type="range" 
                      min="0.5" 
                      max="2.0" 
                      step="0.05" 
                      value={role.scale || 1.0} 
                      onChange={(e) => updateRole(role.id, { scale: parseFloat(e.target.value) })} 
                      className="flex-1 h-1.5 bg-slate-100 rounded-full appearance-none cursor-pointer accent-tm-maroon" 
                    />
                    <span className="text-[9px] font-mono text-slate-400">{(role.scale || 1.0).toFixed(1)}x</span>
                  </div>
                </div>
              ))}
            </div>
          </section>
        </div>
      </div>

      <div className="w-full lg:w-[55%] bg-[#E2E8F0] flex flex-col items-center justify-center p-6 lg:p-12 sticky top-0 print:p-0">
        <div className="mb-8 flex gap-4 no-print z-50">
          <button onClick={handleDownloadImage} disabled={isDownloading} className="flex items-center gap-3 px-8 py-4 bg-tm-blue text-white rounded-2xl font-black uppercase tracking-widest hover:shadow-2xl transition-all disabled:opacity-50">
            {isDownloading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Download className="w-5 h-5" />}
            <span>{isDownloading ? 'Saving...' : 'Export PNG'}</span>
          </button>
        </div>
        <div id="flyer-preview-container" ref={flyerRef} className="w-full max-w-[480px] shadow-2xl bg-tm-blue aspect-[3/4] relative print:shadow-none">
          <FlyerCanvas details={details} roles={roles} backgroundUrl={backgroundUrl} bgOpacity={bgOpacity} photoStyle={photoStyle} />
        </div>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { MapPin, Calendar, Clock, Users, Shield, Zap } from 'lucide-react';
import { RolePlayer, MeetingDetails } from '../types.ts';

interface FlyerCanvasProps {
  details: MeetingDetails;
  roles: RolePlayer[];
  backgroundUrl: string | null;
  bgOpacity: number;
  photoStyle: 'circle' | 'square';
  layoutPattern?: 'standard' | 'staggered' | 'focus';
}

interface RoleItemProps {
  role?: RolePlayer;
  photoStyle: 'circle' | 'square';
  layoutPattern: 'standard' | 'staggered' | 'focus';
  isFocused?: boolean;
  index?: number;
  variant?: 'normal' | 'large';
  labelIfEmpty?: string;
  themeColor: MeetingDetails['themeColor'];
  isLightBackground: boolean;
  globalScale?: number;
}

const RoleItem: React.FC<RoleItemProps> = ({ 
  role, 
  photoStyle, 
  layoutPattern, 
  isFocused = false, 
  index = 0, 
  variant = 'normal', 
  labelIfEmpty, 
  themeColor, 
  isLightBackground,
  globalScale = 1.0
}) => {
  const frameClass = photoStyle === 'circle' ? 'rounded-full' : 'rounded-2xl';
  const textMainClass = isLightBackground ? 'text-slate-900' : 'text-white';
  const textRoleClass = isLightBackground ? 'text-tm-blue' : 'text-tm-yellow';

  const baseSize = variant === 'large' ? 112 : 64; 
  const combinedScale = (role?.scale || 1.0) * globalScale;
  const finalSize = baseSize * combinedScale;

  const containerWidth = finalSize + 32;

  return (
    <div 
      className={`flex flex-col items-center group animate-in fade-in zoom-in duration-300 min-w-0 shrink-0`}
      style={{ width: `${containerWidth}px` }}
    >
      <div className="relative mb-2 flex justify-center w-full shrink-0">
        <div 
          className={`${frameClass} border-[3px] ${isLightBackground ? 'border-tm-blue/20' : 'border-tm-yellow/40'} overflow-hidden bg-white/10 shadow-xl transition-all duration-300 shrink-0 transform`}
          style={{ width: `${finalSize}px`, height: `${finalSize}px` }}
        >
          {role?.photoUrl ? (
            <img src={role.photoUrl} className="w-full h-full object-cover" alt={role.name} />
          ) : (
            <div className="w-full h-full flex items-center justify-center">
              <Users className={`w-1/2 h-1/2 ${isLightBackground ? 'text-tm-blue/10' : 'text-tm-yellow/10'}`} />
            </div>
          )}
        </div>
      </div>
      <div className="text-center w-full px-1 overflow-hidden">
        <p className={`${variant === 'large' ? 'text-[7px] sm:text-[8px]' : 'text-[6px] sm:text-[7px]'} font-black ${textRoleClass} uppercase tracking-widest leading-none mb-1 truncate drop-shadow-sm`}>
          {role?.role || labelIfEmpty || "Role"}
        </p>
        <p className={`${variant === 'large' ? 'text-[10px] sm:text-[12px]' : 'text-[9px] sm:text-[10px]'} font-bold ${textMainClass} leading-tight drop-shadow-lg truncate w-full`}>
          {role?.name || "TBA"}
        </p>
      </div>
    </div>
  );
};

const CategorySection: React.FC<{ 
  title: string; 
  icon: any; 
  items: RolePlayer[]; 
  photoStyle: 'circle' | 'square'; 
  layoutPattern: 'standard' | 'staggered' | 'focus'; 
  themeColor: MeetingDetails['themeColor'];
  isLightBackground: boolean;
  globalScale: number;
  isFocusedSection?: boolean 
}> = ({ title, icon: Icon, items, photoStyle, layoutPattern, themeColor, isLightBackground, globalScale, isFocusedSection = false }) => (
  items.length > 0 && (
    <div className="flex flex-col gap-3 w-full items-center shrink-0 mb-4">
      <div className={`flex items-center gap-2 border-b ${isLightBackground ? 'border-tm-blue/10' : 'border-tm-yellow/20'} pb-0.5 w-full max-w-[85%] justify-center`}>
        <Icon className={`w-2.5 h-2.5 ${isLightBackground ? 'text-tm-blue' : 'text-tm-yellow'} shrink-0`} />
        <h3 className={`text-[6px] lg:text-[7px] font-black tracking-[0.3em] uppercase ${isLightBackground ? 'text-tm-blue' : 'text-tm-yellow'} truncate`}>{title}</h3>
      </div>
      <div className={`flex flex-wrap justify-center items-start w-full gap-x-3 sm:gap-x-4 lg:gap-x-6 gap-y-4`}>
        {items.map((role, i) => (
          <RoleItem 
            key={role.id} 
            role={role} 
            photoStyle={photoStyle} 
            layoutPattern={layoutPattern} 
            isFocused={isFocusedSection} 
            index={i}
            themeColor={themeColor}
            isLightBackground={isLightBackground}
            globalScale={globalScale}
          />
        ))}
      </div>
    </div>
  )
);

const FlyerCanvas: React.FC<FlyerCanvasProps> = ({ 
  details, 
  roles, 
  backgroundUrl, 
  bgOpacity, 
  photoStyle, 
  layoutPattern = 'standard' 
}) => {
  const themeColor = details.themeColor || 'blue';
  const globalPhotoScale = details.globalPhotoScale || 1.0;

  let baseColorClass = 'bg-tm-blue';
  let isLightBackground = false;

  switch (themeColor) {
    case 'maroon': baseColorClass = 'bg-tm-maroon'; break;
    case 'grey': baseColorClass = 'bg-tm-grey'; isLightBackground = true; break;
    case 'yellow': baseColorClass = 'bg-tm-yellow'; isLightBackground = true; break;
    case 'midnight': baseColorClass = 'bg-slate-950'; break;
    default: baseColorClass = 'bg-tm-blue';
  }

  // Ensure no one is hidden: anyone not in "Leadership" keywords goes to "Support"
  const leadership = roles.filter(r => ['TMOD', 'TTM', 'GENERAL EVALUATOR', 'GE', 'LEAD', 'CHAIR'].some(k => r.role.toUpperCase().includes(k)));
  const support = roles.filter(r => !leadership.includes(r));

  const textMainClass = isLightBackground ? 'text-slate-900' : 'text-white';
  const textAccentClass = isLightBackground ? 'text-tm-blue' : 'text-tm-yellow';
  const badgeClass = isLightBackground ? 'bg-tm-blue text-white' : 'bg-tm-maroon/90 text-tm-yellow';
  const badgeRounding = details.badgeShape === 'modern' ? 'rounded-xl' : 'rounded-full';
  const headerFont = details.titleFont === 'serif' ? 'font-brand' : 'font-header';

  const logoUrl = "https://i.postimg.cc/V6m9zvZR/logo.jpg";

  return (
    <div className={`relative w-full h-full flex flex-col font-sans overflow-hidden transition-all duration-500 ${baseColorClass}`}>
      <div className="absolute inset-0 z-0">
        {backgroundUrl ? (
          <img src={backgroundUrl} className="w-full h-full object-cover transition-opacity duration-300" style={{ opacity: bgOpacity / 100 }} alt="Flyer Background" />
        ) : (
          <div className={`w-full h-full bg-gradient-to-br from-black/20 to-black/60`} />
        )}
        <div className={`absolute inset-0 ${isLightBackground ? 'bg-white/10' : 'bg-black/20'}`} />
      </div>

      <div className={`relative z-10 flex flex-col h-full ${textMainClass} p-4 sm:p-5 lg:p-6 pt-5`}>
        <div className={`absolute top-0 right-0 left-0 h-1 ${isLightBackground ? 'bg-tm-blue' : 'bg-tm-yellow'}`} />

        <div className="mb-4 flex flex-col items-center text-center shrink-0 w-full overflow-hidden">
          <div className="mb-2">
             <img src={logoUrl} alt="TM Logo" className="h-8 sm:h-10 w-auto object-contain rounded bg-white p-0.5 shadow-sm" />
          </div>
          <div className="flex flex-col text-center overflow-hidden mb-1">
              <span className={`text-[5px] lg:text-[6px] font-black tracking-[0.4em] uppercase ${textAccentClass}`}>TOASTMASTERS INTERNATIONAL</span>
              <span className={`text-[9px] lg:text-[11px] font-bold uppercase tracking-widest truncate mx-auto`}>{details.clubName}</span>
          </div>
          <h1 className={`text-lg sm:text-xl lg:text-2xl ${headerFont} font-black mb-1.5 drop-shadow-2xl uppercase truncate w-full tracking-tight px-2`}>
            {details.title}
          </h1>
          <div className={`${badgeClass} py-1 px-6 ${badgeRounding} border border-white/20 shadow-xl max-w-[90%] mx-auto overflow-hidden`}>
            <p className={`text-[8px] sm:text-[10px] lg:text-[11px] font-bold italic truncate`}>
              <span className="not-italic mr-1">{details.themeLabel}</span>
              {details.theme}
            </p>
          </div>
        </div>

        <div className="flex-1 flex flex-col min-h-0 w-full overflow-hidden">
          {details.flyerType === 'spotlight' ? (
             <div className="flex-1 flex flex-wrap items-center justify-center gap-x-6 gap-y-8 px-4 py-6 overflow-y-auto no-scrollbar">
               {roles.map((role) => (
                 <RoleItem key={role.id} role={role} photoStyle={photoStyle} layoutPattern="standard" variant={roles.length <= 2 ? 'large' : 'normal'} themeColor={themeColor} isLightBackground={isLightBackground} globalScale={globalPhotoScale} />
               ))}
             </div>
          ) : (
             <div className="flex-1 flex flex-col gap-6 min-h-0 overflow-y-auto no-scrollbar py-2">
               <CategorySection title={details.leadershipLabel || "Leadership"} icon={Shield} items={leadership} photoStyle={photoStyle} layoutPattern={layoutPattern} isFocusedSection={true} themeColor={themeColor} isLightBackground={isLightBackground} globalScale={globalPhotoScale} />
               <CategorySection title={details.supportLabel || "Support Roles"} icon={Zap} items={support} photoStyle={photoStyle} layoutPattern={layoutPattern} themeColor={themeColor} isLightBackground={isLightBackground} globalScale={globalPhotoScale} />
             </div>
          )}
        </div>

        <div className={`mt-3 pt-3 border-t ${isLightBackground ? 'border-tm-blue/10' : 'border-white/10'} shrink-0`}>
          <div className={`grid grid-cols-3 gap-1 ${isLightBackground ? 'bg-white/90' : 'bg-black/80'} backdrop-blur-md rounded-xl p-3 shadow-xl`}>
            <div className="flex flex-col items-center text-center gap-0.5 overflow-hidden">
              <Calendar className={`w-3.5 h-3.5 ${textAccentClass}`} />
              <p className="text-[8px] sm:text-[10px] font-bold">{new Date(details.date).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}</p>
            </div>
            <div className={`flex flex-col items-center text-center gap-0.5 border-x ${isLightBackground ? 'border-tm-blue/10' : 'border-white/10'} px-1`}>
              <Clock className={`w-3.5 h-3.5 ${textAccentClass}`} />
              <p className="text-[8px] sm:text-[10px] font-bold">{details.time}</p>
            </div>
            <div className="flex flex-col items-center text-center gap-0.5">
              <MapPin className={`w-3.5 h-3.5 ${textAccentClass}`} />
              <p className="text-[7px] sm:text-[9px] font-bold leading-tight line-clamp-2 text-center break-words">{details.location}</p>
            </div>
          </div>
          <p className={`mt-2 text-center text-[7px] ${textAccentClass} opacity-80 uppercase font-black tracking-[0.5em]`}>WHERE LEADERS ARE MADE</p>
        </div>
      </div>
    </div>
  );
};

export default FlyerCanvas;

