  time: string;
  location: string;
  clubName: string;
  flyerType: 'full' | 'spotlight';
  themeColor: 'blue' | 'maroon' | 'grey' | 'yellow' | 'midnight' | 'royal' | 'sunset' | 'ocean' | 'platinum';
